   103→// validateConfig validates the deployment configuration
   104→func validateConfig(config DeployConfig) error {
   105→	if config.App == "" {
   106→		return fmt.Errorf("app name is required")
   107→	}
   108→	if config.ControllerURL == "" {
   109→		return fmt.Errorf("controller URL is required")
   110→	}
   111→	return nil
   112→}
   113→
   114→// buildDeployURL constructs the deployment URL with query parameters
   115→func buildDeployURL(config DeployConfig) string {
   116→	url := fmt.Sprintf("%s/apps/%s/builds?sha=%s",
   117→		config.ControllerURL, config.App, config.SHA)
   118→
   119→	if config.MainClass != "" {
   120→		url += "&main=" + utils.URLQueryEsc(config.MainClass)
   121→	}
   122→
   123→	if config.Lane != "" {
   124→		url += "&lane=" + config.Lane
   125→	}
   126→
   127→	if config.IsPlatform {
   128→		url += "&platform=true"
   129→	}
   130→
   131→	if config.BlueGreen {
   132→		url += "&blue_green=true"
   133→	}
   134→
   135→	if config.Environment != "" {
   136→		url += "&env=" + config.Environment
   137→	}
   138→
   139→	return url
   140→}
   141→
   142→// parseDeployResponse parses the HTTP response into a DeployResult
   143→func parseDeployResponse(resp *http.Response, config DeployConfig) (*DeployResult, error) {
   144→	// Get the target domain
   145→	domain := getTargetDomain(config)
   146→
   147→	// Construct the result
   148→	result := &DeployResult{
   149→		Success:      resp.StatusCode == http.StatusOK,
   150→		Version:      config.SHA,
   151→		DeploymentID: resp.Header.Get("X-Deployment-ID"),
   152→		URL:          fmt.Sprintf("https://%s.%s", config.App, domain),
   153→		Message:      "Deployment completed",
   154→	}
   155→
   156→	// Add error message if not successful
   157→	if !result.Success {
   158→		result.Message = fmt.Sprintf("Deployment failed with status %d", resp.StatusCode)
   159→	}
   160→
   161→	return result, nil
   162→}
   163→
   164→// getTargetDomain returns the appropriate domain based on platform and environment
   165→func getTargetDomain(config DeployConfig) string {
   166→	if config.IsPlatform {
   167→		if config.Environment == "dev" {
   168→			return "dev.ployman.app"
   169→		}
   170→		return "ployman.app"
   171→	}
   172→
   173→	if config.Environment == "dev" {
   174→		return "dev.ployd.app"
   175→	}
   176→	return "ployd.app"
   177→}
